   * @param params - Thông tin audit log
   * @param identity - Thông tin user identity (optional)
   */
  async createAuditLog(params: CreateAuditLogParams, identity?: UserIdentity): Promise<AuditLog> {
    const auditLog = new AuditLog();

    // Gán thông tin chính
    auditLog.action = params.action;
    auditLog.entityType = params.entityType;
    auditLog.entityId = params.entityId;
    auditLog.oldValues = params.oldValues;
    auditLog.newValues = params.newValues;
    auditLog.description = params.description;
    auditLog.module = params.module;
    auditLog.isSystemAction = params.isSystemAction || false;

    // Gán thông tin user identity (ưu tiên từ params, fallback từ identity)
    auditLog.userId = params.userId || identity?.userId;
    auditLog.userName = params.userName || identity?.userName;
    auditLog.ipAddress = params.ipAddress || identity?.ipAddress;
    auditLog.userAgent = params.userAgent || identity?.userAgent;

    return this.auditLogRepo.save(auditLog);
  }

  /**
