    entityType: string,
    entityId: string,
    newValues: Record<string, any>,
    identity?: UserIdentity,
    options?: { module?: string; description?: string },
  ): Promise<AuditLog> {
    return this.createAuditLog(
      {
        action: AuditAction.CREATE,
        entityType,
        entityId,
        newValues,
        module: options?.module,
        description: options?.description || `Created ${entityType} with ID: ${entityId}`,
      },
      identity,
    );
  }

