  async findAllPaginated(params: AuditLogQueryParams): Promise<HttpPaginatedResponse<AuditLog>> {
    const { page, size, searchText, sortBy, sortDirection } = params;
    const skip = (page - 1) * size;

    const qb = this.auditLogRepo.createQueryBuilder('entity');

    if (searchText) {
      qb.andWhere(
        '(entity.entityType ILIKE :search OR entity.description ILIKE :search OR entity.userName ILIKE :search)',
        { search: `%${searchText}%` },
      );
    }

    qb.orderBy(`entity.${sortBy}`, sortDirection as 'ASC' | 'DESC')
      .skip(skip)
      .take(size);

    const [items, total] = await qb.getManyAndCount();

    return new HttpPaginatedResponse<AuditLog>().withItems(items).withTotal(total).withPage(page).withSize(size);
  }

  findAll() {
    return this.auditLogRepo.findAndCount();
  }

  findById(id: number) {
    return this.auditLogRepo.findOne({ where: { id } });
