import { JsonController, Get, Param, QueryParams } from 'routing-controllers';
import { OpenAPI } from 'routing-controllers-openapi';
import { Service } from 'typedi';

import { HttpPaginatedResponse } from '@Libs/types/HttpPaginatedResponse';

import { AuditAction } from '@Enums/AuditLog';

import { AuditLog } from '@Entities/AuditLog';

import { AuditLogService } from '@Services/AuditLogService';

import { AuditLogQueryParams } from '@Rests/types/AuditLogDto';

@Service()
@JsonController('/audit-logs')
export class AuditLogController {
  constructor(private readonly service: AuditLogService) {}

  @Get('')
  @OpenAPI({ summary: 'List AuditLog (paginated)' })
  list(@QueryParams() params: AuditLogQueryParams): Promise<HttpPaginatedResponse<AuditLog>> {
    return this.service.findAllPaginated(params);
  }

  @Get('/by-entity/:entityType/:entityId')
  @OpenAPI({ summary: 'Get audit logs by entity type and ID' })
  getByEntity(@Param('entityType') entityType: string, @Param('entityId') entityId: string) {
    return this.service.findByEntity(entityType, entityId);
  }

  @Get('/by-user/:userId')
  @OpenAPI({ summary: 'Get audit logs by user ID' })
  getByUser(@Param('userId') userId: string) {
    return this.service.findByUser(userId);
  }

  @Get('/by-action/:action')
  @OpenAPI({ summary: 'Get audit logs by action' })
  getByAction(@Param('action') action: AuditAction) {
    return this.service.findByAction(action);
  }

  @Get('/:id')
  @OpenAPI({ summary: 'Get AuditLog by id' })
  get(@Param('id') id: number) {
    return this.service.findById(id);
  }
}

