+  private buildAuditChanges<T extends Record<string, any>>(updateData: T, previousState?: Record<string, any>) {
+    const oldValues: Record<string, any> = {};
+    const newValues: Record<string, any> = {};
+
+    Object.entries(updateData || {}).forEach(([key, value]) => {
+      if (typeof value === 'undefined') {
+        return;
+      }
+
+      newValues[key] = value;
+
+      if (previousState && Object.prototype.hasOwnProperty.call(previousState, key)) {
+        oldValues[key] = previousState[key];
+      }
+    });
+
+    return { oldValues, newValues };
